class DataRequest{constructor(r,t){if(!r)throw new Error("Shepherd Pro: Missing required apiKey option.");if(!t)throw new Error("Shepherd Pro: Missing required apiPath option.");this.apiKey=r,this.apiPath=t}async sendEvents(r){try{const e=await fetch(this.apiPath+"/api/v1/actor",{headers:{Authorization:"ApiKey "+this.apiKey,"Content-Type":"application/json"},method:"POST",body:JSON.stringify(r)});if(!e.ok)throw new Error("Could not create an event 🐑");var t=(await e.json())["data"];return t}catch(r){throw new Error("Error fetching data:"+(r instanceof Error?r.message:"Unknown error"))}}}export{DataRequest as default};